    diag_vals = [IDENTITY_MATRIX[i,i] for i in 1:106]
    if diag_vals == FIRMA_106
        println("✅ Firma cuántica intacta.")
        return true
    else
        println("❌ Firma cuántica CORRUPTA.")
        return false
    end
end
